import java.sql.*;

public class SecureSQLInjectionExample {
    public static void main(String[] args) {
        try {
            String userInput = "'; DROP TABLE users; --"; // User input with SQL Injection payload

            // Connection to the database
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a parameterized SQL statement
            String sql = "SELECT * FROM users WHERE username = ?";
            PreparedStatement preparedStatement = connection.prepareStatement(sql);

            // Set the user input as a parameter in the prepared statement
            preparedStatement.setString(1, userInput);

            // Execute the prepared statement
            ResultSet resultSet = preparedStatement.executeQuery();

            // Process the result set (not shown in this example)
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

